exercises.solution:
class TodoList {
  items: { task: string; done: boolean }[];

  constructor() {
    this.items = [];
  }

  add(task: string): void {
    this.items.push({ task, done: false });
  }

  complete(task: string): void {
    const item = this.items.find(i => i.task === task);
    if (item) {
      item.done = true;
    }
  }

  summary(): string {
    const doneCount = this.items.filter(i => i.done).length;
    return `${doneCount}/${this.items.length} completed`;
  }
}

const todos = new TodoList();
todos.add("Learn TS");
todos.add("Build app");
todos.add("Deploy");
todos.complete("Learn TS");
console.log(todos.summary());

